import UIKit

// MARK: - Network Configuration

enum APIEnvironment {
    case production
    case legacy
    
    var baseURL: String {
        switch self {
        case .production:
            return "https://api.example.com"
        case .legacy:
            return "http://legacy.internal"
        }
    }
}

// MARK: - Network Error

enum NetworkError: Error, LocalizedError {
    case invalidURL
    case noData
    case decodingError(Error)
    case httpError(Int)
    case networkError(Error)
    case atsBlocked
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .noData:
            return "No data received"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .httpError(let code):
            return "HTTP error with status code: \(code)"
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .atsBlocked:
            return "Connection blocked by App Transport Security. Check ATS exceptions."
        }
    }
}

// MARK: - API Response Models

struct APIResponse<T: Codable>: Codable {
    let status: String
    let data: T?
    let message: String?
}

struct User: Codable {
    let id: Int
    let name: String
    let email: String
}

struct LegacyRecord: Codable {
    let recordId: String
    let value: String
    let timestamp: String
}

// MARK: - Network Manager

class NetworkManager: NSObject {
    static let shared = NetworkManager()
    
    private var secureSession: URLSession!
    private var insecureSession: URLSession!
    
    private override init() {
        super.init()
        
        // Secure session for HTTPS connections (api.example.com)
        let secureConfig = URLSessionConfiguration.default
        secureConfig.timeoutIntervalForRequest = 30
        secureConfig.timeoutIntervalForResource = 60
        secureConfig.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        secureSession = URLSession(configuration: secureConfig, delegate: self, delegateQueue: nil)
        
        // Insecure session for HTTP connections (legacy.internal)
        let insecureConfig = URLSessionConfiguration.default
        insecureConfig.timeoutIntervalForRequest = 60
        insecureConfig.timeoutIntervalForResource = 120
        insecureConfig.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        insecureSession = URLSession(configuration: insecureConfig, delegate: self, delegateQueue: nil)
    }
    
    private func session(for environment: APIEnvironment) -> URLSession {
        switch environment {
        case .production:
            return secureSession
        case .legacy:
            return insecureSession
        }
    }
    
    // MARK: - Generic Request Method
    
    func request<T: Codable>(
        environment: APIEnvironment,
        endpoint: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        let urlString = "\(environment.baseURL)\(endpoint)"
        
        guard let url = URL(string: urlString) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let urlSession = session(for: environment)
        
        let task = urlSession.dataTask(with: request) { data, response, error in
            if let error = error {
                let nsError = error as NSError
                // Check if this is an ATS error
                if nsError.domain == NSURLErrorDomain &&
                    (nsError.code == NSURLErrorAppTransportSecurityRequiresSecureConnection ||
                     nsError.code == NSURLErrorSecureConnectionFailed) {
                    DispatchQueue.main.async {
                        completion(.failure(.atsBlocked))
                    }
                    return
                }
                DispatchQueue.main.async {
                    completion(.failure(.networkError(error)))
                }
                return
            }
            
            if let httpResponse = response as? HTTPURLResponse,
               !(200...299).contains(httpResponse.statusCode) {
                DispatchQueue.main.async {
                    completion(.failure(.httpError(httpResponse.statusCode)))
                }
                return
            }
            
            guard let data = data else {
                DispatchQueue.main.async {
                    completion(.failure(.noData))
                }
                return
            }
            
            do {
                let decoded = try JSONDecoder().decode(T.self, from: data)
                DispatchQueue.main.async {
                    completion(.success(decoded))
                }
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(.decodingError(error)))
                }
            }
        }
        
        task.resume()
    }
    
    // MARK: - Async/Await Support
    
    @available(iOS 15.0, *)
    func request<T: Codable>(
        environment: APIEnvironment,
        endpoint: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil
    ) async throws -> T {
        let urlString = "\(environment.baseURL)\(endpoint)"
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let urlSession = session(for: environment)
        
        do {
            let (data, response) = try await urlSession.data(for: request)
            
            if let httpResponse = response as? HTTPURLResponse,
               !(200...299).contains(httpResponse.statusCode) {
                throw NetworkError.httpError(httpResponse.statusCode)
            }
            
            let decoded = try JSONDecoder().decode(T.self, from: data)
            return decoded
        } catch let error as NetworkError {
            throw error
        } catch let error as DecodingError {
            throw NetworkError.decodingError(error)
        } catch {
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain &&
                (nsError.code == NSURLErrorAppTransportSecurityRequiresSecureConnection ||
                 nsError.code == NSURLErrorSecureConnectionFailed) {
                throw NetworkError.atsBlocked
            }
            throw NetworkError.networkError(error)
        }
    }
}

// MARK: - URLSessionDelegate for SSL handling

extension NetworkManager: URLSessionDelegate {
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        let host = challenge.protectionSpace.host
        
        if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust {
            if host == "api.example.com" {
                // For production, use default SSL validation
                completionHandler(.performDefaultHandling, nil)
            } else if host.hasSuffix("legacy.internal") || host == "legacy.internal" {
                // For legacy internal systems, accept the server trust
                // This is necessary for self-signed certificates on internal systems
                if let serverTrust = challenge.protectionSpace.serverTrust {
                    let credential = URLCredential(trust: serverTrust)
                    completionHandler(.useCredential, credential)
                } else {
                    completionHandler(.performDefaultHandling, nil)
                }
            } else {
                completionHandler(.performDefaultHandling, nil)
            }
        } else {
            completionHandler(.performDefaultHandling, nil)
        }
    }
}

// MARK: - API Service Layer

class APIService {
    static let shared = APIService()
    private let networkManager = NetworkManager.shared
    
    // MARK: - Production API Calls
    
    func fetchUsers(completion: @escaping (Result<APIResponse<[User]>, NetworkError>) -> Void) {
        networkManager.request(
            environment: .production,
            endpoint: "/v1/users",
            completion: completion
        )
    }
    
    func createUser(name: String, email: String, completion: @escaping (Result<APIResponse<User>, NetworkError>) -> Void) {
        let body: [String: Any] = ["name": name, "email": email]
        let bodyData = try? JSONSerialization.data(withJSONObject: body)
        
        networkManager.request(
            environment: .production,
            endpoint: "/v1/users",
            method: "POST",
            body: bodyData,
            completion: completion
        )
    }
    
    // MARK: - Legacy System Calls
    
    func fetchLegacyRecords(completion: @escaping (Result<[LegacyRecord], NetworkError>) -> Void) {
        networkManager.request(
            environment: .legacy,
            endpoint: "/api/records",
            completion: completion
        )
    }
    
    func syncLegacyRecord(recordId: String, completion: @escaping (Result<LegacyRecord, NetworkError>) -> Void) {
        networkManager.request(
            environment: .legacy,
            endpoint: "/api/records/\(recordId)/sync",
            method: "POST",
            completion: completion
        )
    }
    
    // MARK: - Async/Await versions
    
    @available(iOS 15.0, *)
    func fetchUsers() async throws -> APIResponse<[User]> {
        try await networkManager.request(
            environment: .production,
            endpoint: "/v1/users"
        )
    }
    
    @available(iOS 15.0, *)
    func fetchLegacyRecords() async throws -> [LegacyRecord] {
        try await networkManager.request(
            environment: .legacy,
            endpoint: "/api/records"
        )
    }
}

// MARK: - ATS Configuration Validator

class ATSConfigurationValidator {
    static func validateATSConfiguration() {
        print("=== ATS Configuration Validation ===")
        
        // Check production endpoint
        validateEndpoint(
            url: "https://api.example.com",
            description: "Production API (HTTPS)"
        )
        
        // Check legacy endpoint
        validateEndpoint(
            url: "http://legacy.internal",
            description: "Legacy System (HTTP)"
        )
    }
    
    private static func validateEndpoint(url urlString: String, description: String) {
        guard let url = URL(string: urlString) else {
            print("❌ \(description): Invalid URL")
            return
        }
        
        let semaphore = DispatchSemaphore(value: 0)
        
        let task = URLSession.shared.dataTask(with: url) { _, response, error in
            if let error = error {
                let nsError = error as NSError
                if nsError.code == NSURLErrorAppTransportSecurityRequiresSecureConnection {
                    print("❌ \(description): Blocked by ATS - Add exception for \(url.host ?? "unknown")")
                } else {
                    print("⚠️ \(description): Network error - \(error.localizedDescription)")
                }
            } else if let httpResponse = response as? HTTPURLResponse {
                print("✅ \(description): Connected (HTTP \(httpResponse.statusCode))")
            }
            semaphore.signal()
        }
        
        task.resume()
        _ = semaphore.wait(timeout: .now() + 10)
    }
}

// MARK: - View Model

class MainViewModel: ObservableObject {
    @Published var users: [User] = []
    @Published var legacyRecords: [LegacyRecord] = []
    @Published var errorMessage: String?
    @Published var isLoading = false
    @Published var connectionStatus: [String: Bool] = [
        "Production (HTTPS)": false,
        "Legacy (HTTP)": false
    ]
    
    private let apiService = APIService.shared
    
    func fetchAllData() {
        isLoading = true
        errorMessage = nil
        
        let group = DispatchGroup()
        
        // Fetch from production API
        group.enter()
        apiService.fetchUsers { [weak self] result in
            defer { group.leave() }
            switch result {
            case .success(let response):
                self?.users = response.data ?? []
                self?.connectionStatus["Production (HTTPS)"] = true
            case .failure(let error):
                self?.errorMessage = "Production API: \(error.localizedDescription)"
                self?.connectionStatus["Production (HTTPS)"] = false
            }
        }
        
        // Fetch from legacy system
        group.enter()
        apiService.fetchLegacyRecords { [weak self] result in
            defer { group.leave() }
            switch result {
            case .success(let records):
                self?.legacyRecords = records
                self?.connectionStatus["Legacy (HTTP)"] = true
            case .failure(let error):
                let existing = self?.errorMessage ?? ""
                self?.errorMessage = existing.isEmpty ? "Legacy System: \(error.localizedDescription)" : "\(existing)\nLegacy System: \(error.localizedDescription)"
                self?.connectionStatus["Legacy (HTTP)"] = false
            }
        }
        
        group.notify(queue: .main) { [weak self] in
            self?.isLoading = false
        }
    }
    
    @available(iOS 15.0, *)
    func fetchAllDataAsync() async {
        await MainActor.run { isLoading = true; errorMessage = nil }
        
        async let usersTask: Void = {
            do {
                let response: APIResponse<[User]> = try await self.apiService.fetchUsers()
                await MainActor.run {
                    self.users = response.data ?? []
                    self.connectionStatus["Production (HTTPS)"] = true
                }
            } catch {
                await MainActor.run {
                    self.errorMessage = "Production API: \(error.localizedDescription)"
                    self.connectionStatus["Production (HTTPS)"] = false
                }
            }
        }()
        
        async let legacyTask: Void = {
            do {
                let records: [LegacyRecord] = try await self.apiService.fetchLegacyRecords()
                await MainActor.run {
                    self.legacyRecords = records
                    self.connectionStatus["Legacy (HTTP)"] = true
                }
            } catch {
                await MainActor.run {
                    let existing = self.errorMessage ?? ""
                    self.errorMessage = existing.isEmpty ? "Legacy: \(error.localizedDescription)" : "\(existing)\nLegacy: \(error.localizedDescription)"
                    self.connectionStatus["Legacy (HTTP)"] = false
                }
            }
        }()
        
        _ = await (usersTask, legacyTask)
        
        await MainActor.run { isLoading = false }
    }
}

