import SwiftUI

struct ContentView: View {
    @StateObject private var viewModel = MainViewModel()
    
    var body: some View {
        NavigationView {
            List {
                // Connection Status Section
                Section(header: Text("Connection Status")) {
                    ForEach(Array(viewModel.connectionStatus.keys.sorted()), id: \.self) { key in
                        HStack {
                            Image(systemName: viewModel.connectionStatus[key] == true ? "checkmark.circle.fill" : "xmark.circle.fill")
                                .foregroundColor(viewModel.connectionStatus[key] == true ? .green : .red)
                            Text(key)
                            Spacer()
                            Text(viewModel.connectionStatus[key] == true ? "Connected" : "Disconnected")
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                }
                
                // ATS Configuration Info
                Section(header: Text("ATS Configuration")) {
                    ATSInfoRow(title: "api.example.com", protocol: "HTTPS", tlsVersion: "TLS 1.2+", status: "Secure")
                    ATSInfoRow(title: "legacy.internal", protocol: "HTTP", tlsVersion: "N/A", status: "Exception")
                }
                
                // Error Section
                if let error = viewModel.errorMessage {
                    Section(header: Text("Errors")) {
                        Text(error)
                            .foregroundColor(.red)
                            .font(.caption)
                    }
                }
                
                // Users from Production API
                Section(header: Text("Users (Production API - HTTPS)")) {
                    if viewModel.users.isEmpty && !viewModel.isLoading {
                        Text("No users loaded")
                            .foregroundColor(.secondary)
                    }
                    ForEach(viewModel.users, id: \.id) { user in
                        VStack(alignment: .leading, spacing: 4) {
                            Text(user.name)
                                .font(.headline)
                            Text(user.email)
                                .font(.subheadline)
                                .foregroundColor(.secondary)
                        }
                        .padding(.vertical, 4)
                    }
                }
                
                // Legacy Records
                Section(header: Text("Records (Legacy System - HTTP)")) {
                    if viewModel.legacyRecords.isEmpty && !viewModel.isLoading {
                        Text("No legacy records loaded")
                            .foregroundColor(.secondary)
                    }
                    ForEach(viewModel.legacyRecords, id: \.recordId) { record in
                        VStack(alignment: .leading, spacing: 4) {
                            Text("Record: \(record.recordId)")
                                .font(.headline)
                            Text(record.value)
                                .font(.subheadline)
                            Text(record.timestamp)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                        .padding(.vertical, 4)
                    }
                }
            }
            .navigationTitle("API Client")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button(action: {
                        viewModel.fetchAllData()
                    }) {
                        if viewModel.isLoading {
                            ProgressView()
                        } else {
                            Image(systemName: "arrow.clockwise")
                        }
                    }
                    .disabled(viewModel.isLoading)
                }
                
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Validate ATS") {
                        ATSConfigurationValidator.validateATSConfiguration()
                    }
                }
            }
            .onAppear {
                viewModel.fetchAllData()
            }
        }
    }
}

struct ATSInfoRow: View {
    let title: String
    let `protocol`: String
    let tlsVersion: String
    let status: String
    
    var body: some View {
        VStack(alignment: .leading, spacing: 4) {
            Text(title)
                .font(.headline)
            HStack {
                Label(`protocol`, systemImage: `protocol` == "HTTPS" ? "lock.fill" : "lock.open.fill")
                    .font(.caption)
                    .foregroundColor(`protocol` == "HTTPS" ? .green : .orange)
                Spacer()
                Text("TLS: \(tlsVersion)")
                    .font(.caption)
                    .foregroundColor(.secondary)
                Spacer()
                Text(status)
                    .font(.caption)
                    .padding(.horizontal, 8)
                    .padding(.vertical, 2)
                    .background(status == "Secure" ? Color.green.opacity(0.2) : Color.orange.opacity(0.2))
                    .cornerRadius(4)
            }
        }
        .padding(.vertical, 4)
    }
}

// MARK: - App Entry Point

@main
struct APIClientApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}

// MARK: - Info.plist Generator Helper

class InfoPlistATSGenerator {
    static func generateATSPlistXML() -> String {
        return """
        <?xml version="1.0" encoding="UTF-8"?>
        <!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
        <plist version="1.0">
        <dict>
            <key>NSAppTransportSecurity</key>
            <dict>
                <!-- Do NOT set NSAllowsArbitraryLoads to true -->
                <!-- Instead, use specific domain exceptions -->
                <key>NSAllowsArbitraryLoads</key>
                <false/>
                
                <key>NSExceptionDomains</key>
                <dict>
                    <!-- Production API - Enforce strong TLS -->
                    <key>api.example.com</key>
                    <dict>
                        <key>NSExceptionMinimumTLSVersion</key>
                        <string>TLSv1.2</string>
                        <key>NSExceptionRequiresForwardSecrecy</key>
                        <true/>
                        <key>NSIncludesSubdomains</key>
                        <true/>
                    </dict>
                    
                    <!-- Legacy Internal System - Allow insecure HTTP -->
                    <key>legacy.internal</key>
                    <dict>
                        <key>NSExceptionAllowsInsecureHTTPLoads</key>
                        <true/>
                        <key>NSIncludesSubdomains</key>
                        <true/>
                        <key>NSExceptionMinimumTLSVersion</key>
                        <string>TLSv1.0</string>
                        <key>NSExceptionRequiresForwardSecrecy</key>
                        <false/>
                    </dict>
                </dict>
            </dict>
        </dict>
        </plist>
        """
    }
}